// Парсим HTML список откликов с Хабра
// ВАЖНО: обновить селекторы после анализа реального HTML

const html = $input.first().json.data;

// Используем простой regex для быстрого парсинга
// В продакшне лучше использовать cheerio через Code node с npm
const responses = [];

// Ищем ссылки на профили кандидатов
const linkRegex = /href="(\/resumes\/[^"]+|https:\/\/career\.habr\.com\/[^"]+\/resumes\/[^"]+)"/g;
const nameRegex = /<a[^>]*class="[^"]*name[^"]*"[^>]*>([^<]+)<\/a>/g;

let match;
const seen = new Set();

// TODO: заменить на реальные селекторы после проверки HTML
// Этот блок — заглушка, требует адаптации
const itemRegex = /data-response-id="([^"]+)"/g;
while ((match = itemRegex.exec(html)) !== null) {
  const id = match[1];
  if (!seen.has(id)) {
    seen.add(id);
    responses.push({
      external_id: id,
      source: 'habr',
      raw_html_fragment: '' // будет заполнено при реальном парсинге
    });
  }
}

return responses.map(r => ({ json: r }));

// Парсим резюме: гражданство, опыт, локация, должность
const html = $input.first().json.data;

function extractText(html, regex) {
  const m = html.match(regex);
  return m ? m[1].trim() : null;
}

const citizenship = extractText(html, /Гражданство[^:]*:[\s]*([А-Яа-яA-Za-z\s]+)/i);

const expStr = extractText(html, /Опыт[\s]+работы[^:]*:[\s]*([\d\s]+(?:лет|год|года|месяц[а-в]*)?)/i);

const location = extractText(html, /<span[^>]*class="[^"]*location[^"]*"[^>]*>([^<]+)<\/span>/i);

const position = extractText(html, /<h1[^>]*class="[^"]*title[^"]*"[^>]*>([^<]+)<\/h1>/i);

// Нормализация гражданства
function normalizeCitizenship(raw) {
  if (!raw) return null;
  const s = raw.toLowerCase().trim();
  if (s.includes('россия') || s.includes('russia')) return 'RU';
  return 'OTHER';
}

// Нормализация опыта (в годах)
function parseExp(raw) {
  if (!raw) return null;
  let months = 0;
  const y = raw.match(/(\d+)\s*(лет|год|года)/);
  const m = raw.match(/(\d+)\s*(месяц|месяца|месяцев)/);
  if (y) months += parseInt(y[1]) * 12;
  if (m) months += parseInt(m[1]);
  return months > 0 ? Math.round(months / 12 * 10) / 10 : null;
}

const citizenshipNorm = normalizeCitizenship(citizenship);
const experienceYears = parseExp(expStr);

// Фильтрация
let qualified = null;
let filter_reason = null;

if (citizenshipNorm === 'OTHER') {
  qualified = false;
  filter_reason = 'Гражданство: ' + citizenship;
} else if (experienceYears !== null && experienceYears < 5) {
  qualified = false;
  filter_reason = 'Опыт менее 5 лет: ' + experienceYears;
} else {
  const issues = [];
  if (citizenshipNorm === null) issues.push('гражданство не указано');
  if (experienceYears === null) issues.push('опыт не указан');
  if (issues.length > 0) {
    qualified = null; // 🟡
    filter_reason = 'Нет данных: ' + issues.join(', ');
  } else {
    qualified = true; // ✅
  }
}

return [{
  json: {
    ...$input.first().json,
    citizenship: citizenshipNorm,
    citizenship_raw: citizenship,
    experience_years: experienceYears,
    experience_raw: expStr,
    location,
    position,
    qualified,
    filter_reason,
  }
}];
